// Text locators - Most user-facing and resilient
import { test, expect } from '@playwright/test';

test('text-based locators', async ({ page }) => {
  await page.goto('https://playwright.dev');

  // Exact text match
  await page.locator('text=Get Started').click();

  // Partial text match
  await page.locator('text=Get').click(); // Finds "Get Started"

  // Case-insensitive
  await page.locator('text=get started').click(); // Still works!

  // With regex
  await page.locator('text=/Get .*/').click();

  // Shorthand using page methods
  await page.click('text=Get Started');

  // Using getByText (recommended)
  await page.getByText('Get Started').click();
  await page.getByText(/Get Started/i).click(); // With regex

  // Partial match with getByText
  await page.getByText('Get', { exact: false }).click();
});

// Pro tip: Text locators are best because they match what users see

// Role-based locators - Accessibility-friendly and semantic
import { test } from '@playwright/test';

test('role-based locators', async ({ page }) => {
  await page.goto('https://example.com');

  // Find by ARIA role
  await page.getByRole('button').click();
  await page.getByRole('link').click();
  await page.getByRole('textbox').fill('Hello');
  await page.getByRole('checkbox').check();

  // Combine role with name (accessible name)
  await page.getByRole('button', { name: 'Submit' }).click();
  await page.getByRole('link', { name: 'Learn more' }).click();

  // With regex
  await page.getByRole('button', { name: /submit/i }).click();

  // Common roles:
  await page.getByRole('heading').click();      // <h1>, <h2>, etc.
  await page.getByRole('button').click();       // <button>
  await page.getByRole('link').click();         // <a>
  await page.getByRole('textbox').fill('text'); // <input type="text">
  await page.getByRole('checkbox').check();     // <input type="checkbox">
  await page.getByRole('radio').check();        // <input type="radio">
  await page.getByRole('combobox').click();     // <select>

  // Filter by level (for headings)
  await page.getByRole('heading', { level: 1 }).textContent();

  // Filter by pressed state
  await page.getByRole('button', { pressed: true }).click();

  // Filter by expanded state
  await page.getByRole('button', { expanded: true }).click();
});

// Why use roles?
// - Promotes accessible HTML
// - Semantic and meaningful
// - Survives styling changes

// CSS and XPath selectors - Traditional but powerful
import { test } from '@playwright/test';

test('CSS selectors', async ({ page }) => {
  await page.goto('https://example.com');

  // CSS selectors
  await page.locator('button').click();           // Tag name
  await page.locator('.submit-btn').click();      // Class
  await page.locator('#login-form').fill('text'); // ID
  await page.locator('[type="email"]').fill('user@test.com'); // Attribute

  // Combining selectors
  await page.locator('button.primary').click();   // Tag + class
  await page.locator('input[name="email"]').fill('test@example.com');

  // Pseudo-selectors
  await page.locator('li:first-child').click();
  await page.locator('li:last-child').click();
  await page.locator('li:nth-child(3)').click();

  // Attribute contains
  await page.locator('[class*="submit"]').click(); // Contains "submit"
  await page.locator('[href^="/admin"]').click(); // Starts with "/admin"
  await page.locator('[href$=".pdf"]').click();   // Ends with ".pdf"

  // Descendant selectors
  await page.locator('form input').fill('text');  // Any descendant
  await page.locator('form > input').fill('text'); // Direct child
});

test('XPath selectors', async ({ page }) => {
  await page.goto('https://example.com');

  // XPath (less common in Playwright, but available)
  await page.locator('xpath=//button').click();
  await page.locator('xpath=//button[@type="submit"]').click();
  await page.locator('xpath=//div[contains(@class, "container")]').click();

  // XPath advantages: Can navigate up the DOM tree
  await page.locator('xpath=//button/parent::div').click();

  // But prefer CSS when possible - it's faster and more readable
});

// When to use CSS/XPath:
// - When text/role locators don't work
// - For complex DOM navigation
// - When you have data-testid attributes

// Test ID locators - Most stable for test automation
import { test } from '@playwright/test';

test('test ID locators', async ({ page }) => {
  await page.goto('https://example.com');

  // Using data-testid attribute (default)
  await page.getByTestId('submit-button').click();
  await page.getByTestId('email-input').fill('test@example.com');
  await page.getByTestId('user-profile').click();

  // Alternative: using locator
  await page.locator('[data-testid="submit-button"]').click();
});

// HTML with test IDs:
/*
<button data-testid="submit-button">Submit</button>
<input data-testid="email-input" type="email" />
<div data-testid="user-profile">
  <h2>John Doe</h2>
</div>
*/

// Custom test ID attribute
// In playwright.config.ts:
/*
use: {
  testIdAttribute: 'data-test-id' // or 'data-automation-id'
}
*/

// Then use:
test('custom test ID', async ({ page }) => {
  await page.getByTestId('submit').click(); // Finds data-test-id="submit"
});

// Benefits of test IDs:
// ✓ Most stable - won't break with UI changes
// ✓ Clear intent - this element is for testing
// ✓ Fast - no complex selector parsing
// ✓ Works with any element type

// Drawbacks:
// ✗ Requires adding attributes to HTML
// ✗ Not user-facing (doesn't match user perspective)
// ✗ Extra work for developers

// Advanced locator techniques
import { test, expect } from '@playwright/test';

test('locator chaining', async ({ page }) => {
  await page.goto('https://example.com');

  // Chain locators to narrow down search
  const form = page.locator('form');
  const emailInput = form.locator('input[type="email"]');
  await emailInput.fill('test@example.com');

  // Or in one line
  await page.locator('form').locator('input[type="email"]').fill('test@example.com');

  // Find within a specific area
  const sidebar = page.locator('.sidebar');
  await sidebar.locator('text=Settings').click();

  // Multiple levels
  await page
    .locator('.container')
    .locator('form')
    .locator('button[type="submit"]')
    .click();
});

test('filtering locators', async ({ page }) => {
  await page.goto('https://example.com');

  // Filter by text
  await page
    .locator('button')
    .filter({ hasText: 'Submit' })
    .click();

  // Filter by NOT having text
  await page
    .locator('button')
    .filter({ hasNotText: 'Cancel' })
    .click();

  // Filter by having a child element
  await page
    .locator('article')
    .filter({ has: page.locator('button.delete') })
    .click();

  // Filter by NOT having a child element
  await page
    .locator('article')
    .filter({ hasNot: page.locator('.archived') })
    .click();

  // Combine multiple filters
  await page
    .locator('div')
    .filter({ hasText: 'Product' })
    .filter({ has: page.locator('button') })
    .click();
});

test('selecting specific items', async ({ page }) => {
  await page.goto('https://example.com');

  // First and last
  await page.locator('li').first().click();
  await page.locator('li').last().click();

  // By index (0-based)
  await page.locator('li').nth(2).click(); // 3rd item

  // Get count
  const count = await page.locator('li').count();
  console.log(`Found ${count} items`);

  // Iterate through all matches
  const items = page.locator('li');
  for (let i = 0; i < await items.count(); i++) {
    const text = await items.nth(i).textContent();
    console.log(text);
  }

  // Better: use all()
  const allItems = await page.locator('li').all();
  for (const item of allItems) {
    console.log(await item.textContent());
  }
});

test('has() and hasText() methods', async ({ page }) => {
  await page.goto('https://example.com');

  // Find article containing a button
  await page.locator('article', { has: page.locator('button') }).click();

  // Find article with specific text
  await page.locator('article', { hasText: 'Breaking News' }).click();

  // Combine both
  await page.locator('article', {
    has: page.locator('button'),
    hasText: 'Featured'
  }).click();
});

// Pro tip: Chain and filter to create precise, readable locators

